import { useEffect, useState } from 'react'
import { geoData } from '@fs/zion-config'
import PropTypes from 'prop-types'

import locationByCountryCode from './locationByCountryCode'
import useGeoLocation from './useGeoLocation'

// An arguably more reasonable default center than 0,0.
// Used as a last resort if no other center is available.
const LEHI_FAMILY_SEARCH_CENTER = {
  latitude: 40.4276,
  longitude: -111.9005,
}

export default function useCenter({ initialLatitude, initialLongitude }) {
  const [center, setCenter] = useState()
  const { geoLocation, loading } = useGeoLocation()

  // Set the center
  useEffect(() => {
    if (!loading) {
      const locationByCountryCodeResult = locationByCountryCode(
        geoData?.country || (typeof window !== 'undefined' ? window.SERVER_DATA?.geoData?.country : undefined)
      )

      let latitude =
        initialLatitude ??
        geoData?.latitude ??
        window?.SERVER_DATA?.geoData?.latitude ??
        geoLocation?.latitude ??
        locationByCountryCodeResult?.latitude ??
        LEHI_FAMILY_SEARCH_CENTER.latitude

      if (typeof latitude === 'string') {
        latitude = Number.parseFloat(latitude)
      }

      let longitude =
        initialLongitude ??
        geoData?.longitude ??
        window?.SERVER_DATA?.geoData?.longitude ??
        geoLocation?.longitude ??
        locationByCountryCodeResult?.longitude ??
        LEHI_FAMILY_SEARCH_CENTER.longitude

      if (typeof longitude === 'string') {
        longitude = Number.parseFloat(longitude)
      }

      setCenter({
        latitude,
        longitude,
      })
    }
  }, [geoLocation, initialLatitude, initialLongitude, loading])

  return { center, loading }
}

useCenter.propTypes = {
  initialLatitude: PropTypes.number,
  initialLongitude: PropTypes.number,
}
