import React, { forwardRef, lazy, Suspense } from 'react'
import PropTypes from 'prop-types'

import useMap from '../../../internal/components/shared/hooks/useMap'

const AzureMarker = lazy(() => import('../../../internal/components/AzureMap/Marker/Marker'))
const BingMarker = lazy(() => import('../../../internal/components/BingMap/Marker/Marker'))
const GoogleMarker = lazy(() => import('../../../internal/components/GoogleMap/Marker/Marker'))

const Marker = forwardRef(
  (
    {
      ariaLabel,
      chars,
      color = 'red',
      draggable = false,
      focused = false,
      Icon,
      imageSrc,
      info,
      label,
      latitude,
      longitude,
      metadata,
      onBlur,
      onClick,
      onDragEnd,
      onFocus,
      onInfoClosed,
      onMouseEnter,
      onMouseLeave,
      onChange,
      testId,
    },
    ref
  ) => {
    const { azure, bing } = useMap()

    const props = {
      ariaLabel,
      chars,
      color: color ?? 'red',
      draggable,
      focused,
      Icon,
      imageSrc,
      info,
      label,
      latitude,
      longitude,
      metadata,
      onBlur,
      onClick,
      onDragEnd,
      onFocus,
      onInfoClosed,
      onMouseEnter,
      onMouseLeave,
      onChange,
      testId,
    }

    return (
      <Suspense fallback={null}>
        {azure && !bing && <AzureMarker {...props} ref={ref} />}
        {bing && <BingMarker {...props} ref={ref} />}
        {!azure && !bing && <GoogleMarker {...props} ref={ref} />}
      </Suspense>
    )
  }
)

Marker.displayName = 'Marker'

export default Marker

/**
 * @typedef {object} MarkerEventResponse
 * @property {any} metadata - Any custom metadata associated with the marker.
 * @property {object} position - The position of the marker when the event took place.
 * @property {number} position.latitude - The latitude of the marker when the event took place.
 * @property {number} position.longitude - The longitude of the marker when the event took place.
 */

/**
 * @typedef {object} MarkerOnChangeResponse
 * @property {Function} [openInfo] - Function to open the marker's info overlay. Only present if the marker has an info prop
 */

Marker.propTypes = {
  /**
   * The aria-label to use for the marker.
   */
  ariaLabel: PropTypes.string.isRequired,

  /**
   * A set of characters or a number to show on the marker.
   *
   * A maximum of 5 characters will be displayed.
   * Numbers greater than 9999 will be displayed as '9999+'.
   *
   * If used as a fallback for an image and there is only one character, it will be styled as a monogram.
   */
  chars: PropTypes.oneOfType([PropTypes.number, PropTypes.string]),

  /**
   * The color theme to use for the marker.
   */
  color: PropTypes.oneOf(['blue', 'gray', 'green', 'purple', 'red', 'yellow']),

  /**
   * Makes the marker draggable if no label or description is specified.
   *
   * <details>
   * <summary>&nbsp;How to drag a marker with the keyboard</summary>
   * 1. Press the tab key until markers are focused.
   *  - Use the arrow key to move to the desired marker (Google Only).
   * 2. To activate dragging, press Option (⌥) + Space or Option (⌥) + Enter (Mac), Alt + Space or Alt + Enter (Windows).
   * 3. Use the arrow keys to move the marker.
   * 4. To drop the marker at its new location, press Space or Enter. This will also turn dragging off.
   * 5. To turn dragging off and return the marker to its previous position, press Esc.
   * </details>
   */
  draggable: PropTypes.bool,

  /**
   * Whether the marker is currently styled as focused or not.
   */
  focused: PropTypes.bool,

  /**
   * An Icon from '@fs/zion-icon'.
   *
   * If both `Icon` and `chars` are provided, `Icon` will be used.
   *
   * [See the list of available icons](./?path=/docs/ui-foundation-icons--all-icons#available-icons).
   */
  Icon: PropTypes.func,

  /**
   * Source of an image to show in a round marker.
   *
   * If `imageSrc` is provided along with `chars` and/or `Icon`, `imageSrc` will be used.
   *
   * Tip: use `chars` or `Icon` as a fallback if the image fails to load.
   */
  imageSrc: PropTypes.string,

  /**
   * The information to display in a closable overlay when the marker is clicked.
   */
  info: PropTypes.oneOfType([PropTypes.string, PropTypes.func, PropTypes.element, PropTypes.node]),

  /**
   * The label to display in the marker tooltip.
   */
  label: PropTypes.oneOfType([PropTypes.string, PropTypes.func, PropTypes.element, PropTypes.node]),

  /**
   * A number between -90 and 90.
   */
  latitude: PropTypes.number.isRequired,

  /**
   * A number between -180 and 180.
   */
  longitude: PropTypes.number.isRequired,

  /**
   * Any custom metadata to associate with the marker.
   *
   * This is useful for storing data that you want to
   * access when a marker event is triggered.
   */
  metadata: PropTypes.any,

  /**
   * The callback to run when the marker loses focus.
   *
   * @param {MarkerEventResponse} response
   */
  onBlur: PropTypes.func,

  /**
   * The callback to run when the marker is clicked or pressed.
   *
   * Draggable markers will not trigger this event when clicked.
   *
   * @param {MarkerEventResponse} response
   */
  onClick: PropTypes.func,

  /**
   * The callback to run when the marker is done being dragged.
   *
   * @param {MarkerEventResponse} response
   */
  onDragEnd: PropTypes.func,

  /**
   * The callback to run when the marker gains focus.
   *
   * @param {MarkerEventResponse} response
   */
  onFocus: PropTypes.func,

  /**
   * The callback to run when the marker's info overlay is closed.
   */
  onInfoClosed: PropTypes.func,

  /**
   * The callback to run on mouse over of the marker.
   *
   * @param {MarkerEventResponse} response
   */
  onMouseEnter: PropTypes.func,

  /**
   * The callback to run on mouse out of the marker.
   *
   * @param {MarkerEventResponse} response
   */
  onMouseLeave: PropTypes.func,

  /**
   * The callback to run when the marker changes.
   *
   * This is called when the marker is first ready and whenever it changes.
   *
   * @param {MarkerOnChangeResponse} response
   */
  onChange: PropTypes.func,

  /**
   * The test ID to use for the marker.
   */
  testId: PropTypes.string,
}
