import { useEffect, useState } from 'react'
import { kml as kmlToGeoJson } from '@tmcw/togeojson'
import axios from '@fs/zion-axios'
import Cache from '@fs/zion-cache'
import PropTypes from 'prop-types'

const cache = new Cache({
  encrypted: false,
  lifetime: 'oneMonth',
  storeName: 'zion_map_place_coordinates',
  storeVersion: 1,
})

/**
 * Extracts coordinate arrays from GeoJSON features.
 * Handles both Polygon and GeometryCollection types by flattening
 * them into a consistent array of coordinate arrays.
 */
function flatMapHandler(feature) {
  if (feature.geometry.type !== 'Polygon' && feature.geometry.type !== 'GeometryCollection') {
    return []
  }

  return feature.geometry.type === 'Polygon'
    ? [feature.geometry.coordinates[0]]
    : feature.geometry.geometries.map((geometry) => geometry.coordinates[0])
}

/**
 * Selects the most appropriate boundary from a list based on temporal metadata.
 *
 * Priority order:
 * 1. Current boundaries (have from-year but no to-year) - highest priority
 * 2. Historical boundaries with the latest to-year
 * 3. Last boundary in the array (fallback when no temporal metadata exists)
 *
 * Example placeId with years: 393437 (Utah Country)
 *
 * @param {Object} params
 * @param {Array} params.boundaries - Array of boundary objects with title and href properties
 *
 * @returns {string} The href of the selected boundary
 */
function getHrefWithLatestDate({ boundaries }) {
  let latestYear = -Infinity
  let latestHref = ''
  let isCurrent = false

  boundaries.forEach((boundary) => {
    const title = boundary.title || ''
    const fromYearMatch = title.match(/from-year=(\d+)/)
    const toYearMatch = title.match(/to-year=(\d+)/)

    /* If a year-from exists without a year-to, it's assumed to be current
       and takes priority */
    if (fromYearMatch && !toYearMatch && !isCurrent) {
      isCurrent = true
      latestYear = Number.parseInt(fromYearMatch[1], 10)
      latestHref = boundary.href
    } else if (toYearMatch && !isCurrent) {
      const year = Number.parseInt(toYearMatch[1], 10)
      if (year > latestYear) {
        latestYear = year
        latestHref = boundary.href
      }
    }
  })

  if (latestHref === '') {
    return boundaries[boundaries.length - 1].href
  }

  return latestHref
}

/**
 * Fetches and processes boundary coordinates for a given place.
 *
 * This function implements a smart boundary selection strategy:
 * 1. Checks cache first for performance
 * 2. Fetches the place representation to check for a preferredBoundaryId
 * 3. If preferred boundary exists, uses that directly
 * 4. Otherwise, fetches all available boundaries and selects the most appropriate one
 *    based on temporal metadata (current vs historical)
 * 5. Converts KML boundary data to GeoJSON polygons
 * 6. Caches the result for future use
 *
 * @param {Object} params
 * @param {number} params.placeId - The FamilySearch place ID
 * @param {AbortSignal} params.signal - Signal to cancel the request if needed
 *
 * @returns {Promise<Array|null>} Array of polygon coordinate arrays, or null if no boundary found
 */
export async function getPlacesCoordinates({ placeId, signal }) {
  // Check cache first to avoid unnecessary API calls
  const cachedCoordinates = await cache.getItem(`${placeId}`)

  if (cachedCoordinates) {
    return cachedCoordinates
  }

  // Fetch place representation to check for a preferred boundary
  const placeRepresentation = await axios.get(`/service/standards/place/ws/places/reps/${placeId}`, {
    headers: {
      Accept: 'application/json',
    },
    signal,
  })

  let boundaryHref

  if (placeRepresentation.data?.preferredBoundaryId) {
    // Use the explicitly preferred boundary
    const { preferredBoundaryId } = placeRepresentation.data
    boundaryHref = `/service/standards/place/ws/places/reps/${placeId}/boundaries/${preferredBoundaryId}`
  } else {
    // No preferred boundary - fetch all boundaries and select the best one
    const boundariesLinks = await axios.get(`/service/standards/place/ws/places/reps/${placeId}/boundaries/`, {
      headers: {
        Accept: 'application/json',
      },
      signal,
    })

    const boundaries = boundariesLinks.data?.links
    if (!boundaries || boundaries.length === 0) {
      return null
    }

    // Select the most appropriate boundary based on temporal metadata
    boundaryHref = getHrefWithLatestDate({ boundaries })
  }

  if (!boundaryHref) {
    return null
  }

  // Fetch the actual KML boundary data
  const boundaryResponse = await axios.get(boundaryHref, {
    signal,
  })

  // Convert KML to GeoJSON and extract polygon coordinates
  const geoJson = kmlToGeoJson(new DOMParser().parseFromString(boundaryResponse.data, 'text/xml'))
  const polygons = geoJson.features
    .filter((feature) => ['Polygon', 'GeometryCollection'].includes(feature.geometry.type))
    .flatMap(flatMapHandler)

  if (polygons.length) {
    // Cache the processed coordinates for future use
    await cache.setItem(`${placeId}`, polygons)
    return polygons
  }

  return null
}

export default function usePlacesCoordinates({ placeId }) {
  const [coordinates, setCoordinates] = useState()

  useEffect(() => {
    const abortController = new AbortController()

    getPlacesCoordinates({ placeId, signal: abortController.signal })
      .then((result) => {
        if (!abortController.signal.aborted && result) {
          setCoordinates(result)
        }
      })
      .catch((error) => {
        if (error.name === 'AbortError') {
          // Operation was cancelled
        }

        // Swallow non-abort errors here to avoid unhandled promise rejections
      })

    return () => {
      abortController.abort()
    }
  }, [placeId])

  return coordinates
}

usePlacesCoordinates.propTypes = {
  placeId: PropTypes.number.isRequired,
}
