// Calculate the shortest distance between two points on the surface of Earth.
// Returns distance in meters.
export function calculateHaversineDistance({ latitudeOne, latitudeTwo, longitudeOne, longitudeTwo }) {
  const latitudeOneRadians = (latitudeOne * Math.PI) / 180
  const latitudeTwoRadians = (latitudeTwo * Math.PI) / 180
  const deltaLatitudeRadians = ((latitudeTwo - latitudeOne) * Math.PI) / 180
  const deltaLongitudeRadians = ((longitudeTwo - longitudeOne) * Math.PI) / 180

  const haversineOfAngularDistance =
    Math.sin(deltaLatitudeRadians / 2) * Math.sin(deltaLatitudeRadians / 2) +
    Math.cos(latitudeOneRadians) *
      Math.cos(latitudeTwoRadians) *
      Math.sin(deltaLongitudeRadians / 2) *
      Math.sin(deltaLongitudeRadians / 2)

  const centralAngleRadians =
    2 * Math.atan2(Math.sqrt(haversineOfAngularDistance), Math.sqrt(1 - haversineOfAngularDistance))

  return EARTH_RADIUS_METERS * centralAngleRadians
}

export function getStraightLineBearing({ latitudeOne, latitudeTwo, longitudeOne, longitudeTwo }) {
  const longitudeOneRadians = (longitudeOne * Math.PI) / 180
  const latitudeOneRadians = (latitudeOne * Math.PI) / 180
  const longitudeTwoRadians = (longitudeTwo * Math.PI) / 180
  const latitudeTwoRadians = (latitudeTwo * Math.PI) / 180

  const deltaLongitudeRadians = longitudeTwoRadians - longitudeOneRadians

  const y = Math.sin(deltaLongitudeRadians) * Math.cos(latitudeTwoRadians)
  const x =
    Math.cos(latitudeOneRadians) * Math.sin(latitudeTwoRadians) -
    Math.sin(latitudeOneRadians) * Math.cos(latitudeTwoRadians) * Math.cos(deltaLongitudeRadians)

  // Calculate bearing in radians, then convert to degrees
  const bearing = Math.atan2(y, x) * (180 / Math.PI)

  // Normalize to 0-360 degrees
  return (bearing + 360) % 360
}

// Calculate a point at a given distance and bearing from a center point
export function calculatePointAtDistance({ bearingDegrees, latitude, longitude, radiusInMeters }) {
  const bearingRadians = (bearingDegrees * Math.PI) / 180
  const latitudeRadians = (latitude * Math.PI) / 180
  const longitudeRadians = (longitude * Math.PI) / 180
  const angularDistance = radiusInMeters / EARTH_RADIUS_METERS

  const newLatitudeRadians = Math.asin(
    Math.sin(latitudeRadians) * Math.cos(angularDistance) +
      Math.cos(latitudeRadians) * Math.sin(angularDistance) * Math.cos(bearingRadians)
  )

  const newLongitudeRadians =
    longitudeRadians +
    Math.atan2(
      Math.sin(bearingRadians) * Math.sin(angularDistance) * Math.cos(latitudeRadians),
      Math.cos(angularDistance) - Math.sin(latitudeRadians) * Math.sin(newLatitudeRadians)
    )

  return {
    latitude: (newLatitudeRadians * 180) / Math.PI,
    longitude: (newLongitudeRadians * 180) / Math.PI,
  }
}
