import { useEffect, useState } from 'react'
import axios from '@fs/zion-axios'

// Singleton state
let geoLocation
let loading = true
let error = null
let listeners = []
let controller = null
let requestStarted = false

function notifyListeners() {
  listeners.forEach((listener) => listener({ geoLocation, loading, error }))
}

function fetchGeoLocation() {
  if (requestStarted) {
    return
  }

  requestStarted = true
  loading = true
  notifyListeners()
  controller = new AbortController()

  axios
    .get('/service/geolocation/geodata', { signal: controller.signal })
    .then((response) => {
      geoLocation = response.data
      error = null
    })
    .catch((currentError) => {
      if (axios.isCancel?.(currentError) || currentError.name === 'CanceledError') {
        // Request was cancelled, do nothing
      } else {
        geoLocation = null
        error = currentError
      }
    })
    .finally(() => {
      loading = false
      notifyListeners()
    })
}

export default function useGeoLocation() {
  const [state, setState] = useState({ geoLocation, loading, error })

  // Fetch the geolocation and notify listeners
  useEffect(() => {
    const listener = (newState) => setState(newState)
    listeners.push(listener)
    setState({ geoLocation, loading, error })

    if (geoLocation === undefined) {
      fetchGeoLocation()
    } else {
      loading = false
      notifyListeners()
    }

    return () => {
      listeners = listeners.filter((currentListener) => currentListener !== listener)

      if (listeners.length === 0 && controller) {
        controller.abort()
        controller = null
        requestStarted = false
        loading = true
      }
    }
  }, [])

  return { geoLocation: state.geoLocation, loading: state.loading, error: state.error }
}
