import React, {
  Children,
  forwardRef,
  isValidElement,
  lazy,
  Suspense,
  useImperativeHandle,
  useMemo,
  useRef,
  useState,
} from 'react'
import PropTypes from 'prop-types'
import { NoticeLoading } from '@fs/zion-icon'
import { rawDayColors } from '@fs/zion-ui/quarks-authorized-use-only'

import { css } from '@linaria/core'
import useCenter from './hooks/useCenter'
import useBing from './hooks/useBing'
import { ChildrenBoundsProvider } from './hooks/useChildrenBounds'
import Center from '../../internal/components/shared/Center'
import useClusterChildrenBounds from './hooks/useClusterChildrenBounds'

const AzureMap = lazy(() => import('../../internal/components/AzureMap/AzureMap'))
const BingMap = lazy(() => import('../../internal/components/BingMap/BingMap'))
const GoogleMap = lazy(() => import('../../internal/components/GoogleMap/GoogleMap'))

const mapClassName = css`
  block-size: 100%;
  inline-size: 100%;
  overflow: hidden;
  position: relative;
`

const ZionMap = forwardRef(
  (
    {
      azure = false,
      azureSubscriptionKey,
      bing = false,
      bounds,
      children,
      fitMaxZoom,
      fitMinZoom,
      fitToChildrenMode = 'centroid',
      googleApiKey,
      googleMapId = 'DEMO_MAP_ID',
      hideFullscreenControl = false,
      hideMapTypeControl = false,
      initialLatitude,
      initialLongitude,
      initialMapTypeId = 'roadmap',
      initialZoom = 8,
      maxZoom = 18,
      minZoom = 1,
      nonInteractive = false,
      onBoundsChanged,
      onChange,
      onClick,
      onInfoClosed,
      onReady,
      parentScrolls = false,
      skipFitToChildren = false,
      testId,
      userLocation = false,
    },
    ref
  ) => {
    const mapRef = useRef()
    const [container, setContainer] = useState()
    const { loading: useBingLoading, shouldUseBing } = useBing()
    const { loading: useCenterLoading, center } = useCenter({
      initialLatitude,
      initialLongitude,
    })

    useImperativeHandle(ref, () => ({
      closeOverlay: () => mapRef.current?.closeOverlay?.(),
    }))

    const memoizedChildren = useMemo(() => Children.toArray(children), [children])

    const shouldUseAzure = azure && azureSubscriptionKey && !bing && !shouldUseBing
    const hasCluster = memoizedChildren.some((child) => {
      if (!isValidElement(child)) {
        return false
      }

      return child.type?.displayName === 'Cluster'
    })

    const { latitudes, longitudes } = useClusterChildrenBounds({
      children: memoizedChildren,
      hasCluster,
      shouldUseAzure,
    })

    if (useBingLoading || useCenterLoading || !center) {
      return null
    }

    const props = {
      bounds,
      hideFullscreenControl,
      hideMapTypeControl,
      initialLatitude: center.latitude,
      initialLongitude: center.longitude,
      initialMapTypeId: initialMapTypeId ?? 'roadmap',
      initialZoom: initialZoom ?? 8,
      maxZoom: maxZoom ?? 18,
      minZoom: minZoom ?? 1,
      nonInteractive,
      onBoundsChanged,
      onChange,
      onClick,
      onInfoClosed,
      onReady,
      parentScrolls,
      testId,
      userLocation,
    }

    return (
      <div className={mapClassName} ref={setContainer}>
        {container && (
          <ChildrenBoundsProvider
            azure={azure}
            container={container}
            fitMaxZoom={fitMaxZoom}
            fitMinZoom={fitMinZoom}
            fitToChildrenMode={fitToChildrenMode}
            hasCluster={hasCluster}
            initialLatitude={initialLatitude}
            initialLongitude={initialLongitude}
            initialZoom={initialZoom}
            latitudes={latitudes}
            longitudes={longitudes}
            maxZoom={maxZoom}
            minZoom={minZoom}
            skipFitToChildren={skipFitToChildren}
          >
            <Suspense
              fallback={
                <Center>
                  <NoticeLoading color={rawDayColors.gray[100]} size="lg" />
                </Center>
              }
            >
              {shouldUseAzure && (
                <AzureMap {...props} azureSubscriptionKey={azureSubscriptionKey} ref={mapRef}>
                  {children}
                </AzureMap>
              )}
              {(bing || shouldUseBing) && (
                <BingMap {...props} shouldUseBing ref={mapRef}>
                  {children}
                </BingMap>
              )}
              {(!azure || !azureSubscriptionKey) && !bing && !shouldUseBing && (
                <GoogleMap {...props} googleApiKey={googleApiKey} googleMapId={googleMapId} ref={mapRef}>
                  {children}
                </GoogleMap>
              )}
            </Suspense>
          </ChildrenBoundsProvider>
        )}
      </div>
    )
  }
)

ZionMap.displayName = 'ZionMap'

export default ZionMap

const VALID_CHILD_DISPLAY_NAMES = new Set(['Boundary', 'Circle', 'Cluster', 'Marker', 'Path', 'Proximity'])

function childrenValidator(props, propName, componentName) {
  const children = props[propName]

  if (!children || Children.count(children) === 0) {
    return null
  }

  const childArray = Children.toArray(children).filter(Boolean)

  let returnValue = null
  childArray.forEach((child) => {
    if (!isValidElement(child)) {
      returnValue = new Error(
        `Invalid prop \`${propName}\` supplied to \`${componentName}\`. Expected \`Boundary\`, \`Circle\`, \`Cluster\`, \`Marker\`, \`Path\`, or \`Proximity\` components, got \`${child}\`.`
      )
    } else if (!VALID_CHILD_DISPLAY_NAMES.has(child.type?.displayName)) {
      const typeDisplay = (child.type?.displayName ?? child.type).toString()

      returnValue = new Error(
        `Invalid prop \`${propName}\` supplied to \`${componentName}\`. Expected \`Boundary\`, \`Circle\`, \`Cluster\`, \`Marker\`, \`Path\`, or \`Proximity\` components, got a \`${typeDisplay}\` ${child.type?.displayName ? 'component' : 'element'}.`
      )
    }
  })

  return returnValue
}

/**
 * @typedef {object} MapEventResponse
 * @property {object} position - The position of the pointer when the event took place.
 * @property {number} position.latitude - The latitude of the pointer when the event took place.
 * @property {number} position.longitude - The longitude of the pointer when the event took place.
 */

/**
 * @typedef {object} MapOnChangeResponse
 * @property {Function} closeOverlay - Function to close the currently open info overlay
 */

ZionMap.propTypes = {
  /**
   * Renders the map using the Azure Maps API instead of the Bing or Google Maps API.
   */
  azure: PropTypes.bool,

  /**
   * ### **IMPORTANT**
   *
   * Do not reuse a key from a different team/project unless previously approved.
   * This key is unique to your team/project.
   *
   * See: <a href="./?path=/docs/shared-components-map--docs#important">Important Note</a>
   */
  azureSubscriptionKey: PropTypes.string,

  /**
   * Renders the map using the Bing Maps API instead of the Azure or Google Maps API.
   */
  bing: PropTypes.bool,

  /**
   * Defines a boundary that restricts the area of the map accessible to users.
   *
   * If no value is provided and there are children then
   * the map will be fit to and centered on the children.
   *
   * <details>
   * <summary>&nbsp;Additional Details</summary>
   * Use the bounds prop to set maximum visible area of the map.
   * A bounded map will not pan or zoom outside of the given bounds.
   * <br /><br />
   * When set, a user can only pan and zoom while the camera view stays inside the limits of the boundary.
   * Constructs a rectangle from the points at its south-west and north-east corners.
   * <br /><br />
   * Bounds can restrict both longitude and latitude, or can restrict latitude only.
   * Example Utah bounds:<br />
   * <code>
   * bounds: {<br />
   * &nbsp;&nbsp;"north": 42.0016, <br />
   * &nbsp;&nbsp;"south": 36.9977, <br />
   * &nbsp;&nbsp;"east": -109.0416, <br />
   * &nbsp;&nbsp;"west": -114.0522 <br />
   * }<br />
   * </code>
   * <br /><br />
   * For latitude-only bounds use west and east longitudes of -180 and 180, respectively,
   * for example,<br />
   * <code>
   * bounds: {<br />
   * &nbsp;&nbsp;north: northLatitude,<br />
   * &nbsp;&nbsp;south: southLatitude,<br />
   * &nbsp;&nbsp;east: 180,<br />
   * &nbsp;&nbsp;west: -180,<br />
   * }<br />
   * </code>
   * </details>
   * <br />
   */
  bounds: PropTypes.shape({
    north: PropTypes.number,
    south: PropTypes.number,
    east: PropTypes.number,
    west: PropTypes.number,
  }),

  /**
   * Boundary, Circle, Cluster, Marker, Path and/or Proximity components.
   */
  children: childrenValidator,

  /**
   * Maximum zoom level to use when fitting the map to children.
   *
   * A number between 1 and 18. Values outside this range will be ignored.
   *
   * When set, this overrides `maxZoom` specifically for fit-to-children operations.
   * If not set, `maxZoom` will be used instead.
   *
   * This is useful when you want to limit how far the map zooms in when automatically fitting to markers or other children,
   * while still allowing users to manually zoom beyond this limit.
   */
  fitMaxZoom: PropTypes.number,

  /**
   * Minimum zoom level to use when fitting the map to children.
   *
   * A number between 1 and 18. Values outside this range will be ignored.
   *
   * When set, this overrides `minZoom` specifically for fit-to-children operations.
   * If not set, `minZoom` will be used instead.
   *
   * This is useful when you want to ensure the map doesn't zoom out too far when automatically fitting to markers or other children,
   * while still allowing users to manually zoom out beyond this limit.
   */
  fitMinZoom: PropTypes.number,

  /**
   * Controls how the map centers when fitting to Cluster children.
   *
   * - `'centroid'` (default): Centers on the arithmetic mean of all points (influenced by density).
   * - `'geographic'`: Centers on the geographic midpoint between the min/max coordinates (ignores density).
   *
   * <details>
   *  <summary>&nbsp;Additional Details</summary>
   *  If you find that the map is centering too much on clusters of
   *  children and not showing all children, try switching to
   *  geographic mode which finds the midpoint between the furthest
   *  children in each direction instead of the average position of
   *  all children.
   * </details>
   * <br />
   */
  fitToChildrenMode: PropTypes.oneOf(['centroid', 'geographic']),

  /**
   * ### **IMPORTANT**
   *
   * Do not reuse a key from a different team/project unless previously approved.
   * This key is unique to your team/project.
   *
   * See: <a href="./?path=/docs/shared-components-map--docs#important">Important Note</a>
   */
  googleApiKey: PropTypes.string,

  /**
   * A Google Map ID is a unique identifier that represents Google Map styling and configuration settings that are stored in Google Cloud.
   *
   * See: <a href="./?path=/docs/shared-components-map--docs#google-map-id">Google Map Id Note</a>
   */
  googleMapId: PropTypes.string,

  /**
   * Hides the fullscreen control button.
   */
  hideFullscreenControl: PropTypes.bool,

  /**
   * Hides the map type control.
   */
  hideMapTypeControl: PropTypes.bool,

  /**
   * A number between -90 and 90.
   *
   * If `geoData.latitude` is available it will use that as a default value.
   *
   * If `geoData.latitude` is not available then the following map defaults will take effect:
   *
   *   Google: The users current country's capital latitude determined by the users `geodata.country` and a lookup table.
   *   <br>If `geodata.country` is not available: 40.4276 (FamilySearch Lehi, Utah Latitude)
   *
   *   Bing: The users current latitude determined by Microsoft internally.
   */
  initialLatitude: PropTypes.number,

  /**
   * A number between -180 and 180.
   *
   * Otherwise if `geoData.longitude` is available it will use that as a default value.
   *
   * If `geoData.longitude` is not available then the following map defaults will take effect:
   *
   *   Google: The users current country's capital longitude determined by the users `geodata.country` and a lookup table.
   *   <br>If `geodata.country` is not available: -111.9005 (FamilySearch Lehi, Utah Longitude)
   *
   *   Bing: The users current longitude determined by Microsoft internally.
   */
  initialLongitude: PropTypes.number,

  /**
   * The initial map type to display.
   *
   * - **blank**: Displays a blank map with no tiles, a white background, and no map type controls.
   * - **hybrid**: Displays a transparent layer of major streets on satellite images.
   * - **roadmap**: Displays a normal street map (default).
   * - **satellite**: Displays satellite images.
   * - **terrain***: Displays maps with physical features such as terrain and vegetation.
   *
   * \* There is no `terrain` map type in Bing Maps, so selecting terrain will show the roadmap map type.
   */
  initialMapTypeId: PropTypes.oneOf(['blank', 'hybrid', 'roadmap', 'satellite', 'terrain']),

  /**
   * initialZoom values should typically be between 2-18.
   *
   * <details>
   * <summary>&nbsp;Why 2-18?</summary>
   * Google and Azure Maps have different zoom levels.
   * At zoom levels 2-18 they match.
   * </details>
   * <br />
   */
  initialZoom: PropTypes.number,

  /**
   * A number between 1 and 18 and greater than or equal to `minZoom`.
   */
  maxZoom: PropTypes.number,

  /**
   * A number between 1 and 18 and less than or equal to `maxZoom`.
   */
  minZoom: PropTypes.number,

  /**
   * Disables user interaction with the map.
   *
   * This includes panning, zooming, shortcut keys, zoom control, fullscreen control, reset-view/user-location control, and map-type controls.
   *
   * If a draggable marker is being used this should not be set.
   */
  nonInteractive: PropTypes.bool,

  /**
   * A callback function that is called when the viewport bounds have changed.
   *
   * Returns an object with the following properties:
   * - `center`: The center of the map.
   * - `east`: The easternmost longitude of the map.
   * - `north`: The northernmost latitude of the map.
   * - `south`: The southernmost latitude of the map.
   * - `west`: The westernmost longitude of the map.
   * - `zoom`: The current zoom level of the map.
   */
  onBoundsChanged: PropTypes.func,

  /**
   * The callback that is called when the map changes.
   *
   * This is called when the map is first ready and whenever it changes.
   *
   * @param {MapOnChangeResponse} response
   */
  onChange: PropTypes.func,

  /**
   * A callback function that is called when the map is clicked.
   *
   * @param {MapEventResponse} response
   */
  onClick: PropTypes.func,

  /**
   * A callback function that is called when any info overlay is closed on the map.
   *
   * This provides a centralized handler for all info overlay closures,
   * including those from Markers, Clusters, Proximity groups, etc.
   */
  onInfoClosed: PropTypes.func,

  /**
   * The callback to run when the map is ready.
   */
  onReady: PropTypes.func,

  /**
   * Scrolls the parent container instead of the map when using
   * the mouse scroll wheel or when touch-moving on mobile.
   */
  parentScrolls: PropTypes.bool,

  /**
   * If true, the map will not automatically fit to the children.
   *
   * Note that the map will find the optimal zoom level and centroid location for all children if there is a Cluster component.
   */
  skipFitToChildren: PropTypes.bool,

  /**
   * The test ID to use for the map.
   *
   * Defaults to the map type (e.g., 'google-map', 'bing-map', 'azure-map').
   */
  testId: PropTypes.string,

  /**
   * Adds a "Your location" button near the "Reset view" button.
   * Clicking on this button will attempt to set the map center on the
   * user's geolocation and display an info overlay with the location.
   *
   * If the browser does not have geolocation capability or the user blocks
   * geolocation for the website, an error message is displayed.
   */
  userLocation: PropTypes.bool,
}
