import React, { createContext, useCallback, useContext, useEffect, useMemo, useRef, useState } from 'react'
import PropTypes from 'prop-types'
import { calculateCentroidFromCoordinates, getGeographicCenter, getOptimalZoom } from '../utils/utils'

const ChildrenBoundsContext = createContext()
const ChildrenBoundsApiContext = createContext()

export function useChildrenBoundsApi() {
  const context = useContext(ChildrenBoundsApiContext)

  if (!context) {
    throw new Error('useChildrenBounds must be used within a ChildrenBoundsProvider')
  }

  return context
}

export function useChildrenBounds() {
  const context = useContext(ChildrenBoundsContext)

  if (!context) {
    throw new Error('useChildrenBounds must be used within a ChildrenBoundsProvider')
  }

  return context
}

export function ChildrenBoundsProvider({
  azure,
  children,
  container,
  fitMaxZoom,
  fitMinZoom,
  fitToChildrenMode,
  hasCluster,
  initialLatitude,
  initialLongitude,
  initialZoom,
  latitudes,
  longitudes,
  maxZoom,
  minZoom,
  skipFitToChildren,
}) {
  const [collection, setCollection] = useState([])
  const [bounds, setBounds] = useState()
  const [optimalZoom, setOptimalZoom] = useState()
  const [centroidLocation, setCentroidLocation] = useState()
  const addRef = useRef(({ id, latitudes: newLatitudes, longitudes: newLongitudes }) => {
    setCollection((previousCollection) => {
      const existingIndex = previousCollection.findIndex((item) => item.id === id)

      if (existingIndex !== -1) {
        // Update existing entry
        const updated = [...previousCollection]
        updated[existingIndex] = { id, latitudes: newLatitudes, longitudes: newLongitudes }

        return updated
      }

      return [...previousCollection, { id, latitudes: newLatitudes, longitudes: newLongitudes }]
    })
  })
  const removeRef = useRef(({ id }) => {
    setCollection((previousCollection) => {
      if (!previousCollection.some((item) => item.id === id)) {
        return previousCollection
      }

      return previousCollection.filter((item) => item.id !== id)
    })
  })
  const skipNextFitToChildrenRef = useRef()

  const boundsApi = useMemo(
    () => ({
      add: addRef.current,
      remove: removeRef.current,
      skipNextFitToChildrenRef,
      hasCluster,
    }),
    [hasCluster]
  )

  const processNonClusterBounds = useCallback(
    function processNonClusterBounds({ boundsLatitudes, boundsLongitudes }) {
      // Normalize fit zoom values to determine if we have valid constraints
      const normalizedFitMaxZoom =
        fitMaxZoom !== undefined && fitMaxZoom >= 1 && fitMaxZoom <= 18 ? fitMaxZoom : undefined
      const normalizedFitMinZoom =
        fitMinZoom !== undefined && fitMinZoom >= 1 && fitMinZoom <= 18 ? fitMinZoom : undefined

      // When fit constraints are specified, use centroid/optimalZoom path instead of bounds
      // because fitBounds ignores zoom constraints
      if (normalizedFitMaxZoom !== undefined || normalizedFitMinZoom !== undefined) {
        let newCentroidLocation

        if (fitToChildrenMode === 'geographic') {
          // Use geographic center (bounding box midpoint)
          newCentroidLocation = getGeographicCenter({
            latitudes: boundsLatitudes,
            longitudes: boundsLongitudes,
          })
        } else {
          // Default: use centroid (arithmetic mean / average position)
          newCentroidLocation = calculateCentroidFromCoordinates({
            initialLatitude,
            initialLongitude,
            latitudes: boundsLatitudes,
            longitudes: boundsLongitudes,
          })
        }

        const newOptimalZoom = getOptimalZoom({
          azure,
          container,
          fitMaxZoom,
          fitMinZoom,
          initialZoom,
          latitudes: boundsLatitudes,
          longitudes: boundsLongitudes,
          maxZoom,
          minZoom,
        })

        return {
          bounds: undefined,
          centroidLocation: newCentroidLocation,
          optimalZoom: newOptimalZoom,
        }
      }

      // Default path: use bounds (fitBounds will calculate optimal zoom automatically)
      return {
        bounds: {
          east: Math.max(...boundsLongitudes),
          north: Math.max(...boundsLatitudes),
          south: Math.min(...boundsLatitudes),
          west: Math.min(...boundsLongitudes),
        },
        centroidLocation: undefined,
        optimalZoom: undefined,
      }
    },
    [
      azure,
      container,
      fitMaxZoom,
      fitMinZoom,
      fitToChildrenMode,
      initialLatitude,
      initialLongitude,
      initialZoom,
      maxZoom,
      minZoom,
    ]
  )

  const processClusterBounds = useCallback(
    function processClusterBounds({ mergedLatitudes, mergedLongitudes }) {
      let newCentroidLocation

      if (fitToChildrenMode === 'geographic') {
        // Use geographic center (bounding box midpoint)
        newCentroidLocation = getGeographicCenter({
          latitudes: mergedLatitudes.length ? mergedLatitudes : [initialLatitude],
          longitudes: mergedLongitudes.length ? mergedLongitudes : [initialLongitude],
        })
      } else {
        // Default: use centroid (arithmetic mean / average position)
        newCentroidLocation = calculateCentroidFromCoordinates({
          initialLatitude,
          initialLongitude,
          latitudes: mergedLatitudes,
          longitudes: mergedLongitudes,
        })
      }

      const newOptimalZoom = getOptimalZoom({
        azure,
        container,
        fitMaxZoom,
        fitMinZoom,
        initialZoom,
        latitudes: mergedLatitudes,
        longitudes: mergedLongitudes,
        maxZoom,
        minZoom,
      })

      return {
        bounds: undefined,
        centroidLocation: newCentroidLocation,
        optimalZoom: newOptimalZoom,
      }
    },
    [
      azure,
      container,
      fitMaxZoom,
      fitMinZoom,
      fitToChildrenMode,
      initialLatitude,
      initialLongitude,
      initialZoom,
      maxZoom,
      minZoom,
    ]
  )

  // Set the children bounds
  useEffect(() => {
    if (skipFitToChildren || skipNextFitToChildrenRef.current) {
      setBounds(undefined)
      setCentroidLocation(undefined)
      setOptimalZoom(undefined)

      return
    }

    if (!hasCluster && collection.length) {
      const boundsLatitudes = collection.flatMap((item) => item.latitudes)
      const boundsLongitudes = collection.flatMap((item) => item.longitudes)

      const result = processNonClusterBounds({ boundsLatitudes, boundsLongitudes })

      setBounds(result.bounds)

      setCentroidLocation((previousCentroidLocation) => {
        if (!result.centroidLocation) {
          return undefined
        }

        if (
          previousCentroidLocation?.latitude !== result.centroidLocation.latitude ||
          previousCentroidLocation?.longitude !== result.centroidLocation.longitude
        ) {
          return result.centroidLocation
        }

        return previousCentroidLocation
      })

      setOptimalZoom((previousOptimalZoom) => {
        if (previousOptimalZoom !== result.optimalZoom) {
          return result.optimalZoom
        }

        return previousOptimalZoom
      })
    } else if (container && hasCluster && (latitudes?.length || longitudes?.length || collection.length)) {
      // Merge static bounds from useClusterChildrenBounds with dynamic bounds from childrenBoundsApi
      const dynamicLatitudes = collection.flatMap((item) => item.latitudes)
      const dynamicLongitudes = collection.flatMap((item) => item.longitudes)
      const mergedLatitudes = [...(latitudes || []), ...dynamicLatitudes]
      const mergedLongitudes = [...(longitudes || []), ...dynamicLongitudes]

      if (!mergedLatitudes.length || !mergedLongitudes.length) {
        setBounds(undefined)
        setCentroidLocation(undefined)
        setOptimalZoom(undefined)
        return
      }

      const result = processClusterBounds({ mergedLatitudes, mergedLongitudes })

      setBounds(result.bounds)

      setCentroidLocation((previousCentroidLocation) => {
        if (
          previousCentroidLocation?.latitude !== result.centroidLocation.latitude ||
          previousCentroidLocation?.longitude !== result.centroidLocation.longitude
        ) {
          return result.centroidLocation
        }

        return previousCentroidLocation
      })

      setOptimalZoom((previousOptimalZoom) => {
        if (previousOptimalZoom !== result.optimalZoom) {
          return result.optimalZoom
        }

        return previousOptimalZoom
      })
    } else {
      setBounds(undefined)
      setCentroidLocation(undefined)
      setOptimalZoom(undefined)
    }
  }, [
    azure,
    collection,
    container,
    fitMaxZoom,
    fitMinZoom,
    fitToChildrenMode,
    hasCluster,
    initialLatitude,
    initialLongitude,
    initialZoom,
    latitudes,
    longitudes,
    maxZoom,
    minZoom,
    processClusterBounds,
    processNonClusterBounds,
    skipFitToChildren,
  ])

  const value = useMemo(
    () => ({
      bounds,
      optimalZoom,
      centroidLocation,
    }),
    [bounds, optimalZoom, centroidLocation]
  )

  return (
    <ChildrenBoundsApiContext.Provider value={boundsApi}>
      <ChildrenBoundsContext.Provider value={value}>{children}</ChildrenBoundsContext.Provider>
    </ChildrenBoundsApiContext.Provider>
  )
}

ChildrenBoundsProvider.propTypes = {
  children: PropTypes.node,
  fitMaxZoom: PropTypes.number,
  fitMinZoom: PropTypes.number,
  fitToChildrenMode: PropTypes.oneOf(['centroid', 'geographic']),
  skipFitToChildren: PropTypes.bool,
}
