import React, { useState, Suspense, useRef, useEffect } from 'react'
import PropTypes from 'prop-types'
import { useTranslation } from 'react-i18next'
import * as Yup from 'yup'
import { css } from '@linaria/core'
import { i18n } from '@fs/zion-locale'
import { trackLink } from '@fs/zion-analytics'
import { DialogOverlayActions, DialogOverlay, DialogOverlayFooter, Button, colors } from '@fs/zion-ui'
import ZionForm, { useZionForm, FormTextField, FormTextArea } from '@fs/zion-form'
import { yupResolver } from '@hookform/resolvers/yup'
import { NoticeLoading } from '@fs/zion-icon'
import { appConfig } from '@fs/zion-config'
import { LatLngSelect } from '@fs/zion-standards'
import HelpButton from '../HelpButton/HelpButton'

const PlaceError = React.lazy(() => import('../PlaceError/PlaceError'))

const placeMayExistWarningCss = css`
  margin-top: 0;
  background: ${colors.transparent.yellow02};
  color: ${colors.gray90};
  padding: 16px;
  font-size: 12px;
  line-height: 20px;
`

function getValidationSchema() {
  return Yup.object().shape({
    startYear: Yup.number(),
    location: Yup.mixed().test(
      'locationTest',
      i18n.t('provisional-place.enter-valid-lat-lon.warning', 'Please enter a valid lat/long.'),
      (value) => {
        if (!value) return true
        if (/^(-?\d+(\.\d+)?),\s*(-?\d+(\.\d+)?)$/i.test(value)) {
          const pieces = value.split(',')
          return !(pieces[0] > 90 || pieces[0] < -90 || pieces[1] > 180 || pieces[1] < -180)
        }
        return false
      }
    ),
    webAddress: Yup.string(),
    info: Yup.string(),
  })
}

function isValidLatLong(latitude, longitude) {
  const latValid = !Number.isNaN(latitude) && latitude >= -90 && latitude <= 90

  const longValid = !Number.isNaN(longitude) && longitude >= -180 && longitude <= 180
  return latValid && longValid
}

function inputValueToMapLocation(location) {
  const locationSplit = location ? location.split(',') : []
  const lat = locationSplit[0] ? Number.parseFloat(locationSplit[0]) : Number.NaN
  const lng = locationSplit[1] ? Number.parseFloat(locationSplit[1]) : Number.NaN
  return isValidLatLong(lat, lng) ? { lat, lng } : { lat: 40, lng: -112 }
}

function locationToInputString(location) {
  const lat = location ? location.lat || location.latitude : undefined
  const lng = location ? location.lng || location.longitude : undefined
  return lat && lng ? `${lat.toFixed(4)}, ${lng.toFixed(4)}` : ''
}

export default function NewProvisionalPlaceFormShared({
  title,
  subtitle,
  overlay,
  provisionalPlaceFormValues = {},
  onBack,
  onNext,
  onSubmit,
  error,
  isProposed,
}) {
  const [t] = useTranslation()
  const locationRef = useRef()
  const validationSchema = getValidationSchema()
  const [mapZoom, setMapZoom] = useState(8)
  const { placeName = '', parentPlace = null, placeLang = null } = provisionalPlaceFormValues
  const initialValues = { placeName, parentPlace, placeLang }
  const [mapSelected, setMapSelected] = useState(false)
  const hideSubmittedMessage = Boolean(Number(localStorage.getItem('provisional-place-hide-submitted-message')))

  const methods = useZionForm({
    mode: 'all',
    defaultValues: initialValues,
    resolver: yupResolver(validationSchema),
  })
  const {
    reset,
    handleSubmit,
    getValues,
    setValue,
    formState: { isValid },
  } = methods
  const { isOpen, transitioning } = overlay

  const { latitude, longitude } = parentPlace?.selectedItem?.standard?.location || {}
  const defaultLocation = latitude && longitude ? `${latitude}, ${longitude}` : ''
  const inputValue = getValues().location || defaultLocation
  const mapLocation = inputValueToMapLocation(inputValue)

  useEffect(() => {
    if (!isOpen && !transitioning) {
      reset()
    }
  }, [reset, isOpen, transitioning])

  useEffect(() => {
    setTimeout(() => {
      locationRef?.current?.focus()
    })
  }, [])

  return (
    <DialogOverlay
      as={ZionForm}
      methods={methods}
      onSubmit={(values, actions) => {
        if (!isProposed || (isProposed && hideSubmittedMessage)) {
          onSubmit({ values, actions })
        } else {
          onNext({ values })
        }
      }}
      title={title}
      subtitle={subtitle}
      {...overlay}
      closeOnClickAway={false}
    >
      <Suspense fallback={<NoticeLoading />}>
        <div>
          <p className={placeMayExistWarningCss}>
            {t(
              'provisional-place.new-provisional-place.text',
              'FamilySearch will validate these details within 24 hours. If accepted, your new place will be added to the list of standard places.'
            )}
          </p>
          <LatLngSelect
            location={mapLocation}
            onLocation={(newLocation) => {
              setValue('location', locationToInputString(newLocation))
            }}
            zoom={mapZoom}
            onZoom={setMapZoom}
            selectFromMapText={t('provisional-place.select-from-map.text', 'Select "{placeName}" From the Map', {
              placeName,
            })}
            mapSelected={mapSelected}
            setMapSelected={setMapSelected}
            googleApiKey={appConfig.GOOGLE_MAPS_API_KEY}
          />
          <FormTextField
            label={t('provisional-place.location.label', 'Location')}
            name="location"
            placeholder={t('provisional-place.location.place-holder', '40.7608, -111.8903')}
            data-testid="location"
            autoComplete="off"
            clearable
            onClear={() => {
              setValue('location', '')
              setValue('mapLocation', null)
              setMapSelected(false)
            }}
            ref={locationRef}
          />
          <FormTextField
            name="webAddress"
            label={t('provisional-place.web-address.label', 'Source Web Address (URL)')}
            placeholder={t('provisional-place.web-address.place-holder', 'Enter address')}
            autoComplete="off"
          />
          <FormTextArea
            name="info"
            label={t('provisional-place.additional-info.label', 'Additional Information')}
            placeholder={t(
              'provisional-place.additional-info.place-holder',
              'Enter helpful details, citations, and more'
            )}
            autoComplete="off"
            maxLength={1024}
          />
        </div>
        <PlaceError errorType="suggestAPlace" error={error} />
        <DialogOverlayFooter>
          <DialogOverlayActions>
            <HelpButton />
            <Button
              emphasis="medium"
              onClick={() => {
                reset(initialValues)
                onBack()
              }}
            >
              {t('common-ui:back.action', 'Back')}
            </Button>
            <Button
              type="submit"
              emphasis="high"
              onClick={() => {
                handleSubmit()
                trackLink({
                  to: 'familysearch.org',
                  action: 'click_action',
                  name: 'ProvisionalPlace:Create New Place:Click',
                })
              }}
              disabled={!isValid}
            >
              {t('common-ui:cancel.submit', 'Submit')}{' '}
            </Button>
          </DialogOverlayActions>
        </DialogOverlayFooter>
      </Suspense>
    </DialogOverlay>
  )
}

NewProvisionalPlaceFormShared.propTypes = {
  title: PropTypes.string,
  subtitle: PropTypes.string,
  overlay: PropTypes.shape({
    isOpen: PropTypes.bool,
    transitioning: PropTypes.bool,
  }),
  provisionalPlaceFormValues: PropTypes.shape({
    placeName: PropTypes.string,
    parentPlace: PropTypes.object,
    placeLang: PropTypes.object,
  }),
  onBack: PropTypes.func,
  onNext: PropTypes.func,
  onSubmit: PropTypes.func,
  error: PropTypes.object,
  isProposed: PropTypes.bool,
}
