import { Children, isValidElement, useCallback, useEffect, useRef, useState } from 'react'

import { getChildrenPoints, processProximityChild } from '../utils/utils'
import { getPlacesCoordinates } from '../../../internal/components/shared/hooks/usePlacesCoordinates'
import { getBoundsFromCoordinates } from '../../../internal/components/shared/Boundary/utils'

const INITIAL_BOUNDS = {
  latitudes: [],
  longitudes: [],
}

function areBoundsEqual({ firstBounds, secondBounds }) {
  if (firstBounds.latitudes.length !== secondBounds.latitudes.length) {
    return false
  }

  if (firstBounds.longitudes.length !== secondBounds.longitudes.length) {
    return false
  }

  // Compare normalized bounds (min/max) instead of array order
  // to avoid false negatives from nondeterministic Promise.all ordering
  const firstMinLat = Math.min(...firstBounds.latitudes)
  const firstMaxLat = Math.max(...firstBounds.latitudes)
  const firstMinLng = Math.min(...firstBounds.longitudes)
  const firstMaxLng = Math.max(...firstBounds.longitudes)

  const secondMinLat = Math.min(...secondBounds.latitudes)
  const secondMaxLat = Math.max(...secondBounds.latitudes)
  const secondMinLng = Math.min(...secondBounds.longitudes)
  const secondMaxLng = Math.max(...secondBounds.longitudes)

  return (
    firstMinLat === secondMinLat &&
    firstMaxLat === secondMaxLat &&
    firstMinLng === secondMinLng &&
    firstMaxLng === secondMaxLng
  )
}

async function processBoundaryChild({ abortController, child, newBounds }) {
  const coordinates = await getPlacesCoordinates({
    placeId: child.props.placeId,
    signal: abortController.signal,
  })

  if (coordinates && !abortController.signal.aborted) {
    const finalCoordinates = coordinates.map((coords) => [coords])
    const { north, south, east, west } = getBoundsFromCoordinates(finalCoordinates)
    newBounds.latitudes.push(north, south)
    newBounds.longitudes.push(east, west)
  }
}

function processMarkerChild({ child, newBounds }) {
  newBounds.latitudes.push(child.props.latitude)
  newBounds.longitudes.push(child.props.longitude)
}

function processPathChild({ child, math, newBounds }) {
  const points = child.props.points || getChildrenPoints({ children: child.props.children, math })
  points.forEach(({ latitude, longitude }) => {
    newBounds.latitudes.push(latitude)
    newBounds.longitudes.push(longitude)
  })
}

function processProximityChildHandler({ child, math, newBounds }) {
  const proximityPoints = processProximityChild({ child, math })

  proximityPoints.forEach(({ latitude, longitude }) => {
    newBounds.latitudes.push(latitude)
    newBounds.longitudes.push(longitude)
  })
}

async function processChildByType({ abortController, child, math, newBounds }) {
  if (!isValidElement(child)) {
    return
  }

  const displayName = child.type?.displayName

  // Circle registers its own bounds dynamically via childrenBoundsApi to track radius changes.
  // Skip static processing here for Circle to avoid duplication.
  if (displayName === 'Boundary') {
    await processBoundaryChild({ abortController, child, newBounds })
  } else if (displayName === 'Cluster') {
    await Promise.all(
      Children.toArray(child.props?.children).map((clusterChild) =>
        processChildByType({ abortController, child: clusterChild, math, newBounds })
      )
    )
  } else if (displayName === 'Marker') {
    processMarkerChild({ child, newBounds })
  } else if (displayName === 'Path') {
    processPathChild({ child, math, newBounds })
  } else if (displayName === 'Proximity') {
    processProximityChildHandler({ child, math, newBounds })
  }
}

export default function useClusterChildrenBounds({ children, hasCluster, shouldUseAzure }) {
  const [bounds, setBounds] = useState(INITIAL_BOUNDS)
  const boundsRef = useRef(INITIAL_BOUNDS)
  const abortControllerRef = useRef(null)
  const isMountedRef = useRef(true)

  const processChildren = useCallback(async () => {
    // Cancel previous operation if it exists
    if (abortControllerRef.current) {
      abortControllerRef.current.abort()
    }

    const abortController = new AbortController()
    abortControllerRef.current = abortController

    const newBounds = {
      latitudes: [],
      longitudes: [],
    }

    let math = null
    if (shouldUseAzure) {
      const azureMapsControl = await import('azure-maps-control')
      math = azureMapsControl.math
    }

    if (hasCluster) {
      try {
        // Process all map children, including siblings of Cluster components (except for Circle which manages its own bounds)
        await Promise.all(
          children.map(async (child) => {
            // Check if operation was cancelled
            if (abortController.signal.aborted) {
              return
            }
            await processChildByType({ abortController, child, math, newBounds })
          })
        )
      } catch (error) {
        if (error.name === 'AbortError') {
          // Operation was cancelled
        }

        // Swallow non-abort errors here to avoid unhandled promise rejections
      }
    }

    if (
      !abortController.signal.aborted &&
      isMountedRef.current &&
      !areBoundsEqual({ firstBounds: boundsRef.current, secondBounds: newBounds })
    ) {
      boundsRef.current = newBounds
      setBounds(newBounds)
    }
  }, [children, hasCluster, shouldUseAzure])

  useEffect(() => {
    isMountedRef.current = true

    processChildren()

    return () => {
      isMountedRef.current = false

      // Cancel any ongoing operation when component unmounts
      if (abortControllerRef.current) {
        abortControllerRef.current.abort()
      }
    }
  }, [processChildren])

  return bounds
}
