import React, { createContext, useContext, useMemo } from 'react'
import PropTypes from 'prop-types'

const MapContext = createContext()

export default function useMap() {
  const context = useContext(MapContext)

  if (!context) {
    throw new Error('useMap must be used within a MapProvider')
  }

  return context
}

export function MapProvider({
  azure,
  bing,
  children,
  fullscreenContainer,
  gestureHandling,
  getCurrentZoom,
  googleApiKey,
  initialLatitude,
  initialLongitude,
  initialZoom,
  map,
  mapContainer,
  maxZoom,
  nonInteractive,
  onBoundsChanged,
  onZoomChanged,
  skipNextClickRef,
  whenIdle,
  zoomPan,
}) {
  const value = useMemo(
    () => ({
      azure,
      bing,
      fullscreenContainer,
      gestureHandling,
      getCurrentZoom,
      googleApiKey,
      initialLatitude,
      initialLongitude,
      initialZoom,
      map,
      mapContainer,
      maxZoom,
      nonInteractive,
      onBoundsChanged,
      onZoomChanged,
      skipNextClickRef,
      whenIdle,
      zoomPan,
    }),
    [
      azure,
      bing,
      fullscreenContainer,
      gestureHandling,
      getCurrentZoom,
      googleApiKey,
      initialLatitude,
      initialLongitude,
      initialZoom,
      map,
      mapContainer,
      maxZoom,
      nonInteractive,
      onBoundsChanged,
      onZoomChanged,
      skipNextClickRef,
      whenIdle,
      zoomPan,
    ]
  )

  return <MapContext.Provider value={value}>{children}</MapContext.Provider>
}

MapProvider.propTypes = {
  azure: PropTypes.bool,
  bing: PropTypes.bool,
  children: PropTypes.node,
  fullscreenContainer: PropTypes.object,
  gestureHandling: PropTypes.oneOf(['cooperative', 'greedy', 'none', 'auto']),
  googleApiKey: PropTypes.string,
  initialLatitude: PropTypes.number,
  initialLongitude: PropTypes.number,
  initialZoom: PropTypes.number,
  map: PropTypes.object,
  mapContainer: PropTypes.object,
  maxZoom: PropTypes.number,
  nonInteractive: PropTypes.bool,
  onBoundsChanged: PropTypes.shape({
    add: PropTypes.func.isRequired,
    remove: PropTypes.func.isRequired,
  }),
  onZoomChanged: PropTypes.shape({
    add: PropTypes.func.isRequired,
    remove: PropTypes.func.isRequired,
  }),
  skipNextClickRef: PropTypes.object,
  whenIdle: PropTypes.func,
  zoomPan: PropTypes.func,
}
