import { useEffect, useState } from 'react'
import { geoData } from '@fs/zion-config'

import useGeoLocation from './useGeoLocation'

export default function useBing() {
  const [shouldUseBing, setShouldUseBing] = useState(false)
  const { geoLocation, loading } = useGeoLocation()

  const geoLocationCountry = geoLocation?.country

  // Set whether to use Bing or not
  useEffect(() => {
    if (!loading) {
      setShouldUseBing(
        geoData?.country === 'CN' || window?.SERVER_DATA?.geoData?.country === 'CN' || geoLocationCountry === 'CN'
      )
    }
  }, [geoLocationCountry, loading])

  return { loading, shouldUseBing }
}
