import { rawDayColors } from '@fs/zion-ui/quarks-authorized-use-only'

import colors from './colors'

export function getStrokeColor({ color, shade, strokeColor }) {
  if (strokeColor === 'black') {
    return rawDayColors.gray[100]
  }

  if (!shade) {
    return colors[color]?.stroke ?? colors.red.stroke
  }

  const shades = Object.keys(rawDayColors[color]).sort()
  const shadeIndex = shades.indexOf(`${shade}`)
  const strokeIndex = shadeIndex < shades.length - 2 ? shadeIndex + 2 : shadeIndex - 2

  return rawDayColors[color][shades[strokeIndex]]
}

export function getBoundsFromCoordinates(coordinates) {
  const allCoords = coordinates.flat(2)
  let north = -90
  let south = 90
  let east = -180
  let west = 180

  allCoords.forEach((coords) => {
    let latitude
    let longitude
    if (Array.isArray(coords)) {
      latitude = coords[1]
      longitude = coords[0]
    } else {
      latitude = coords.latitude
      longitude = coords.longitude
    }

    if (latitude > north) {
      north = latitude
    }

    if (latitude < south) {
      south = latitude
    }

    if (longitude > east) {
      east = longitude
    }

    if (longitude < west) {
      west = longitude
    }
  })

  return { north, south, east, west }
}
