import { Children, isValidElement } from 'react'

import { calculateHaversineDistance } from '../../../internal/components/shared/utils'

export function getGeographicCenter({ latitudes, longitudes }) {
  if (!latitudes?.length || !longitudes?.length) {
    return { latitude: 0, longitude: 0 }
  }

  const minLatitude = Math.min(...latitudes)
  const maxLatitude = Math.max(...latitudes)
  const minLongitude = Math.min(...longitudes)
  const maxLongitude = Math.max(...longitudes)

  return {
    latitude: (minLatitude + maxLatitude) / 2,
    longitude: (minLongitude + maxLongitude) / 2,
  }
}

export function calculateCentroid({ markers }) {
  if (markers.length === 0) return { latitude: 0, longitude: 0 }

  const sum = markers.reduce(
    (acc, marker) => ({
      latitude: acc.latitude + marker.latitude,
      longitude: acc.longitude + marker.longitude,
    }),
    { latitude: 0, longitude: 0 }
  )

  return {
    latitude: sum.latitude / markers.length,
    longitude: sum.longitude / markers.length,
  }
}

function getCellKey(latitude, longitude, cellSize) {
  const cellX = Math.floor(longitude / cellSize)
  const cellY = Math.floor(latitude / cellSize)

  return `${cellX},${cellY}`
}

function getNeighborCells(cellKey) {
  const [x, y] = cellKey.split(',').map(Number)
  const neighbors = []

  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      neighbors.push(`${x + dx},${y + dy}`)
    }
  }

  return neighbors
}

function buildSpatialIndex(markers, cellSize) {
  const grid = new Map()

  markers.forEach((marker, index) => {
    const cellKey = getCellKey(marker.latitude, marker.longitude, cellSize)

    if (!grid.has(cellKey)) {
      grid.set(cellKey, [])
    }

    grid.get(cellKey).push({ marker, index })
  })

  return grid
}

function findNearbyMarkers(grid, marker, maxDistance, cellSize) {
  const cellKey = getCellKey(marker.latitude, marker.longitude, cellSize)
  const neighborCells = getNeighborCells(cellKey)
  const candidates = []

  neighborCells.forEach((cell) => {
    if (grid.has(cell)) {
      candidates.push(...grid.get(cell))
    }
  })

  return candidates.filter(({ marker: otherMarker }) => {
    const distance = calculateHaversineDistance({
      latitudeOne: marker.latitude,
      latitudeTwo: otherMarker.latitude,
      longitudeOne: marker.longitude,
      longitudeTwo: otherMarker.longitude,
    })

    return distance <= maxDistance
  })
}

const GRID_OPTIMIZATION_FACTOR = 0.7 // Ensures complete coverage while maintaining performance
export function groupMarkersByProximity({ markers, maxDistance = 0 }) {
  if (markers.length === 0) return []

  const cellSize = maxDistance * GRID_OPTIMIZATION_FACTOR
  // Grid-based spatial index for better performance
  const spatialIndex = buildSpatialIndex(markers, cellSize)
  const visited = new Set()
  const groups = []

  markers.forEach((marker, index) => {
    if (visited.has(index)) return

    const group = [marker]
    visited.add(index)

    const nearby = findNearbyMarkers(spatialIndex, marker, maxDistance, cellSize)

    nearby.forEach(({ marker: otherMarker, index: otherIndex }) => {
      if (visited.has(otherIndex) || index === otherIndex) return

      const distance = calculateHaversineDistance({
        inMiles: true,
        latitudeOne: marker.latitude,
        latitudeTwo: otherMarker.latitude,
        longitudeOne: marker.longitude,
        longitudeTwo: otherMarker.longitude,
      })

      if (distance <= maxDistance) {
        group.push(otherMarker)
        visited.add(otherIndex)
      }
    })

    groups.push(group)
  })

  return groups
}

function normalizeCoordinates(latitude, longitude, math) {
  if (!math) return { latitude, longitude }

  return {
    latitude: math.normalizeLatitude(latitude),
    longitude: math.normalizeLongitude(longitude),
  }
}

function extractMarkersFromProximity(proximityChild, math) {
  const markers = []

  Children.forEach(proximityChild.props.children, (grandchild, index) => {
    if (isValidElement(grandchild)) {
      const displayName = grandchild.type?.displayName

      if (displayName === 'Marker') {
        const { latitude, longitude } = grandchild.props
        const normalized = normalizeCoordinates(latitude, longitude, math)

        markers.push({
          ...grandchild.props,
          latitude: normalized.latitude,
          longitude: normalized.longitude,
          originalIndex: index,
        })
      } else if (displayName === 'Path') {
        const points = grandchild.props.points || getChildrenPoints({ children: grandchild.props.children, math })
        points.forEach((point) => {
          const normalized = normalizeCoordinates(point.latitude, point.longitude, math)

          markers.push({
            ...point,
            latitude: normalized.latitude,
            longitude: normalized.longitude,
            originalIndex: index,
          })
        })
      }
    }
  })

  return markers
}

function processProximityGroups(markers, maxDistance, math) {
  const proximityGroups = groupMarkersByProximity({ markers, maxDistance })
  const result = []

  proximityGroups.forEach((group) => {
    if (group.length > 1) {
      const centroid = calculateCentroid({ markers: group })
      const normalized = normalizeCoordinates(centroid.latitude, centroid.longitude, math)

      result.push({
        point: normalized,
        originalIndex: group[0].originalIndex,
      })
    } else {
      const marker = group[0]
      const normalized = normalizeCoordinates(marker.latitude, marker.longitude, math)

      result.push({
        point: normalized,
        originalIndex: marker.originalIndex,
      })
    }
  })

  return result.sort((a, b) => a.originalIndex - b.originalIndex)
}

export function processProximityChild({ child, math }) {
  const markers = extractMarkersFromProximity(child, math)

  if (markers.length === 0) return []

  if (child.props.maxDistance >= 0) {
    const sortedResults = processProximityGroups(markers, child.props.maxDistance, math)
    return sortedResults.map(({ point }) => point)
  }

  return markers.map(({ latitude, longitude }) => normalizeCoordinates(latitude, longitude, math))
}

export function getChildrenPoints({ children, math }) {
  const currentChildrenPoints = []

  Children.forEach(children, (child) => {
    if (!isValidElement(child)) {
      return
    }

    const displayName = child.type?.displayName

    if (displayName === 'Marker') {
      const { latitude, longitude } = child.props
      const normalized = normalizeCoordinates(latitude, longitude, math)
      currentChildrenPoints.push(normalized)
    } else if (displayName === 'Proximity') {
      const proximityPoints = processProximityChild({ child, math })
      currentChildrenPoints.push(...proximityPoints)
    } else if (displayName === 'Path') {
      // Handle Path children that contain Markers
      Children.forEach(child.props.children, (pathChild) => {
        if (isValidElement(pathChild) && pathChild.type?.displayName === 'Marker') {
          const { latitude, longitude } = pathChild.props
          const normalized = normalizeCoordinates(latitude, longitude, math)
          currentChildrenPoints.push(normalized)
        }
      })
    }
  })

  return currentChildrenPoints
}

export function getHashFromString(str) {
  let hash = 0
  for (let i = 0; i < str.length; i++) {
    const char = str.codePointAt(i)
    hash = (hash * 31 + char) % 2147483647
  }

  return Math.abs(hash)
}

export function getHashFromPoints(points) {
  let pointsString = ''
  if (points?.length > 0) {
    pointsString = points.map((point) => `${point.latitude}-${point.longitude}`).join('-')
  }

  return getHashFromString(pointsString)
}

// At zoom level 0, the entire world map is represented as a 256x256 pixel square tile
const WORLD_DIMENSIONS = { width: 256, height: 256 }

// Convert latitude to radians
function latitudeRad({ latitude }) {
  const sin = Math.sin((latitude * Math.PI) / 180)

  const radiansTimesTwo = Math.log((1 + sin) / (1 - sin)) / 2

  return Math.max(Math.min(radiansTimesTwo, Math.PI), -Math.PI) / 2
}

// Calculate zoom level based on fraction of the world to be shown
function zoom({ fraction, containerPx, worldPx }) {
  // Guard against invalid inputs that could lead to Infinity or NaN
  if (!containerPx || !worldPx || containerPx <= 0 || worldPx <= 0) {
    return 0
  }

  // Avoid division by zero or negative/invalid fractions by clamping to a small positive value
  const safeFraction = Math.max(Number.isFinite(fraction) ? fraction : 0, 1e-6)

  const value = containerPx / worldPx / safeFraction
  if (!Number.isFinite(value) || value <= 0) {
    return 0
  }

  const zoomLevel = Math.floor(Math.log2(value))

  return Number.isFinite(zoomLevel) ? zoomLevel : 0
}

export function getOptimalZoom({
  azure,
  container,
  fitMaxZoom,
  fitMinZoom,
  initialZoom = 8,
  latitudes,
  longitudes,
  maxZoom = 18,
  minZoom = 1,
}) {
  if (!latitudes?.length || !container) {
    return initialZoom
  }

  if (!container.offsetHeight || !container.offsetWidth || container.offsetHeight <= 0 || container.offsetWidth <= 0) {
    return initialZoom
  }

  const minLatitude = Math.min(...latitudes)
  const maxLatitude = Math.max(...latitudes)
  const minLongitude = Math.min(...longitudes)
  const maxLongitude = Math.max(...longitudes)

  const latitudeFraction = (latitudeRad({ latitude: maxLatitude }) - latitudeRad({ latitude: minLatitude })) / Math.PI
  const longitudeFraction = (maxLongitude - minLongitude) / 360

  const latitudeZoom = zoom({
    fraction: latitudeFraction,
    containerPx: container.offsetHeight,
    worldPx: WORLD_DIMENSIONS.height,
  })
  const longitudeZoom = zoom({
    fraction: longitudeFraction,
    containerPx: container.offsetWidth,
    worldPx: WORLD_DIMENSIONS.width,
  })

  // Normalize fit zoom values: treat invalid values (< 1, > 18) as undefined
  const normalizedFitMaxZoom = fitMaxZoom !== undefined && fitMaxZoom >= 1 && fitMaxZoom <= 18 ? fitMaxZoom : undefined
  const normalizedFitMinZoom = fitMinZoom !== undefined && fitMinZoom >= 1 && fitMinZoom <= 18 ? fitMinZoom : undefined

  // Use fit-specific zoom limits if provided, otherwise fall back to general limits
  const effectiveMaxZoom = normalizedFitMaxZoom ?? maxZoom
  const effectiveMinZoom = normalizedFitMinZoom ?? minZoom

  const optimalZoom = Math.max(Math.min(latitudeZoom, longitudeZoom, effectiveMaxZoom), effectiveMinZoom)

  return azure ? optimalZoom - 1 : optimalZoom
}

export function calculateCentroidFromCoordinates({ initialLatitude, initialLongitude, latitudes, longitudes }) {
  if (!latitudes?.length || !longitudes?.length) {
    return { latitude: initialLatitude || 0, longitude: initialLongitude || 0 }
  }

  const latitudeSum = latitudes.reduce((acc, currentLatitude) => acc + currentLatitude, 0)
  const longitudeSum = longitudes.reduce((acc, currentLongitude) => acc + currentLongitude, 0)

  return {
    latitude: latitudeSum / latitudes.length,
    longitude: longitudeSum / longitudes.length,
  }
}
